import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures","description":"","frontmatter":{"title":"Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2604.03515-inside-scaffold-taxonomy-arxiv.md","filePath":"research/agent-harness/references/2604.03515-inside-scaffold-taxonomy-arxiv.md","lastUpdated":1779796674000}'),n={name:"research/agent-harness/references/2604.03515-inside-scaffold-taxonomy-arxiv.md"};function s(i,t,l,d,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="inside-the-scaffold-a-source-code-taxonomy-of-coding-agent-architectures" tabindex="-1">Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures <a class="header-anchor" href="#inside-the-scaffold-a-source-code-taxonomy-of-coding-agent-architectures" aria-label="Permalink to &quot;Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.03515" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.03515</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>發表</strong>: 2026-04</li><li><strong>重要性</strong>: Priority A — 首次系統性分類 coding agent 架構，提出 5 個通用控制原語</li></ul><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><p>首次對 <strong>13 個開源 coding agents</strong> 進行源碼層級的架構分析，提出跨 12 維度、3 層組織的統一分類學。</p><h2 id="_3-層組織架構" tabindex="-1">3 層組織架構 <a class="header-anchor" href="#_3-層組織架構" aria-label="Permalink to &quot;3 層組織架構&quot;">​</a></h2><ol><li><strong>控制架構層</strong>: 執行流程的頂層設計</li><li><strong>工具/環境介面層</strong>: 與外部系統互動的邊界</li><li><strong>資源管理層</strong>: Context、記憶、狀態的管理</li></ol><h2 id="_5-個通用控制原語" tabindex="-1">5 個通用控制原語 <a class="header-anchor" href="#_5-個通用控制原語" aria-label="Permalink to &quot;5 個通用控制原語&quot;">​</a></h2><p>這是所有 coding agent 架構的最小可組合基元集合：</p><table tabindex="0"><thead><tr><th>原語</th><th>說明</th></tr></thead><tbody><tr><td><strong>ReAct</strong></td><td>推理-行動交錯（Reason + Act）</td></tr><tr><td><strong>Generate-test-repair</strong></td><td>生成 → 測試 → 修復迴圈</td></tr><tr><td><strong>Plan-execute</strong></td><td>先規劃後執行，分離關注點</td></tr><tr><td><strong>Multi-attempt retry</strong></td><td>多次重試策略</td></tr><tr><td><strong>Tree search</strong></td><td>樹狀搜索（蒙地卡洛等）</td></tr></tbody></table><p><strong>關鍵發現</strong>: <strong>11/13 agents 混合多個原語</strong>，而非單一模式。</p><h2 id="_12-維度變異來源" tabindex="-1">12 維度變異來源 <a class="header-anchor" href="#_12-維度變異來源" aria-label="Permalink to &quot;12 維度變異來源&quot;">​</a></h2><ul><li>控制流管道（固定 vs 蒙地卡洛樹搜尋）</li><li>工具數量（0 到 37 個不等）</li><li>Context 壓縮策略（7 種不同方式）</li></ul><h2 id="對-harness-設計的意義" tabindex="-1">對 Harness 設計的意義 <a class="header-anchor" href="#對-harness-設計的意義" aria-label="Permalink to &quot;對 Harness 設計的意義&quot;">​</a></h2><p>不需要重新發明控制流，而是：</p><ol><li><strong>識別需要哪些原語組合</strong></li><li><strong>設計原語之間的轉換邏輯</strong></li><li><strong>測試與可觀測性使演進自動化</strong></li></ol><h2 id="與本-workspace-的關聯" tabindex="-1">與本 Workspace 的關聯 <a class="header-anchor" href="#與本-workspace-的關聯" aria-label="Permalink to &quot;與本 Workspace 的關聯&quot;">​</a></h2><ul><li>CLAUDE.md 的 multi-step 實作流程 ≈ Plan-execute + Generate-test-repair 組合</li><li>Subagent 委派策略 ≈ Multi-attempt retry + Plan-execute 組合</li><li>/deep-review skill ≈ Generate-test-repair 的 repair 步驟</li></ul><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv Abstract: <a href="https://arxiv.org/abs/2604.03515" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.03515</a></li></ul>',20)])])}const u=e(n,[["render",s]]);export{f as __pageData,u as default};
